namespace sv_e47099682a8a46df93b29d7fcd16cd0a.Models;

public class ApplicationData
{
    // Step 1 – Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2 – Experience
    public List<JobHistoryEntry> JobHistory { get; set; } = [];

    // Step 3 – References
    public List<ReferenceContact> References { get; set; } = [];

    // Track which steps the user has completed
    public HashSet<int> CompletedSteps { get; set; } = [];
}

public class JobHistoryEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

using System.Collections.Concurrent;
using sv_e47099682a8a46df93b29d7fcd16cd0a.Models;

namespace sv_e47099682a8a46df93b29d7fcd16cd0a.Services;

/// <summary>
/// Singleton service that stores wizard state keyed by a session identifier.
/// Both the static layout (SSR) and interactive pages (Server) resolve this
/// from the same DI container and use the cookie-based session key to access
/// the same <see cref="ApplicationData"/> instance.
/// </summary>
public class ApplicationStateStore
{
    private readonly ConcurrentDictionary<string, ApplicationData> _store = new();

    public ApplicationData GetOrCreate(string sessionKey)
        => _store.GetOrAdd(sessionKey, _ => new ApplicationData());

    public void Remove(string sessionKey)
        => _store.TryRemove(sessionKey, out _);
}

