@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject ApplicationStateStore Store
@inject IHttpContextAccessor HttpContextAccessor

@{
    var sessionKey = HttpContextAccessor.HttpContext?
        .Request.Cookies["apply_session"] ?? "";
    var data = string.IsNullOrEmpty(sessionKey) ? null : Store.GetOrCreate(sessionKey);

    var steps = new (string Href, string Label)[]
    {
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience",    "Experience"),
        ("/apply/references",    "References"),
        ("/apply/review",        "Review"),
    };

    var uri = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
    int currentIndex = Array.FindIndex(steps, s => uri.Equals(s.Href, StringComparison.OrdinalIgnoreCase));
    if (currentIndex < 0) currentIndex = 0;
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <div class="wizard-progress">
                <span class="wizard-step-label">Step @(currentIndex + 1) of @steps.Length</span>
                <div class="wizard-steps">
                    @for (int i = 0; i < steps.Length; i++)
                    {
                        var step = steps[i];
                        bool isCurrent = i == currentIndex;
                        bool isCompleted = data?.CompletedSteps.Contains(i + 1) == true;

                        <a href="@step.Href"
                           class="wizard-step @(isCurrent ? "current" : "") @(isCompleted ? "completed" : "")">
                            <span class="wizard-step-number">@(i + 1)</span>
                            <span class="wizard-step-text">@step.Label</span>
                        </a>
                    }
                </div>
            </div>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

.wizard-progress {
    display: flex;
    align-items: center;
    gap: 1rem;
    width: 100%;
}

.wizard-step-label {
    font-weight: 600;
    white-space: nowrap;
}

