    font-size: 0.875rem;
    color: #666;
    background: #e9ecef;
    transition: background 0.2s;
}

.wizard-step:hover {
    background: #dee2e6;
    text-decoration: none;
}

.wizard-step.current {
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
}

.wizard-step.completed {
    background: #198754;
    color: #fff;
}

.wizard-step.completed.current {
    background: #0d6efd;
}

.wizard-step-number {
    display: inline-flex;
