@code {
    private ApplicationData _model = new();
    private string _sessionKey = string.Empty;

    protected override void OnInitialized()
    {
        _sessionKey = EnsureSessionKey();
        var data = Store.GetOrCreate(_sessionKey);
        _model = data;
    }

    private void Next()
    {
        var data = Store.GetOrCreate(_sessionKey);
        data.Name = _model.Name;
        data.Email = _model.Email;
        data.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }

    private string EnsureSessionKey()
    {
        var ctx = HttpContextAccessor.HttpContext;
        var key = ctx?.Request.Cookies["apply_session"];
        if (string.IsNullOrEmpty(key))
        {
            key = Guid.NewGuid().ToString("N");
            ctx?.Response.Cookies.Append("apply_session", key, new CookieOptions
            {
                HttpOnly = true,
                SameSite = SameSiteMode.Strict,
                MaxAge = TimeSpan.FromHours(4)
            });
        }
        return key;
    }
}

