@page "/apply/personal-info"
@layout ApplyLayout
@rendermode InteractiveServer
@inject ApplicationStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Apply – Personal Info</PageTitle>
<h1>Personal Information</h1>

<EditForm Model="_model" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="_model.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="_model.Email" />
    </div>
    <div class="d-flex justify-content-end">
        <button type="submit" class="btn btn-primary">Next &rarr;</button>
    </div>
</EditForm>

@code {
    private ApplicationData _model = new();
    private string _sessionKey = string.Empty;

    protected override void OnInitialized()
    {
        _sessionKey = EnsureSessionKey();
        var data = Store.GetOrCreate(_sessionKey);
        _model = data;
    }

    private void Next()
    {
        var data = Store.GetOrCreate(_sessionKey);
        data.Name = _model.Name;
        data.Email = _model.Email;
        data.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }

    private string EnsureSessionKey()
    {
        var ctx = HttpContextAccessor.HttpContext;
        var key = ctx?.Request.Cookies["apply_session"];
        if (string.IsNullOrEmpty(key))
        {
            key = Guid.NewGuid().ToString("N");
            ctx?.Response.Cookies.Append("apply_session", key, new CookieOptions
            {
                HttpOnly = true,
                SameSite = SameSiteMode.Strict,
                MaxAge = TimeSpan.FromHours(4)
            });
        }
        return key;
    }
}

