toolArgs.file_text:
@page "/apply/review"
@layout ApplyLayout
@rendermode InteractiveServer
@inject ApplicationStateStore Store
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Apply – Review</PageTitle>
<h1>Review Your Application</h1>

<div class="card mb-3">
    <div class="card-header"><strong>Personal Information</strong></div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@_model.Name</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@_model.Email</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header"><strong>Work Experience</strong></div>
    <div class="card-body">
        @if (_model.JobHistory.Count == 0)
        {
            <p class="text-muted mb-0">None provided.</p>
        }
        else
        {
            <table class="table table-sm mb-0">
                <thead><tr><th>Company</th><th>Title</th><th>Years</th></tr></thead>
                <tbody>
                    @foreach (var j in _model.JobHistory)
                    {
                        <tr><td>@j.Company</td><td>@j.Title</td><td>@j.Years</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header"><strong>References</strong></div>
    <div class="card-body">
        @if (_model.References.Count == 0)
        {
            <p class="text-muted mb-0">None provided.</p>
        }
        else
        {
            <table class="table table-sm mb-0">
                <thead><tr><th>Name</th><th>Email</th><th>Relationship</th></tr></thead>
                <tbody>
                    @foreach (var r in _model.References)
                    {
                        <tr><td>@r.Name</td><td>@r.Email</td><td>@r.Relationship</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>
</div>

<div class="d-flex justify-content-between">
    <a href="/apply/references" class="btn btn-secondary">&larr; Back</a>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">
        Your application has been submitted successfully!
    </div>
}

@code {
    private ApplicationData _model = new();
    private string _sessionKey = string.Empty;
    private bool _submitted;

    protected override void OnInitialized()
    {
        _sessionKey = HttpContextAccessor.HttpContext?
            .Request.Cookies["apply_session"] ?? "";
        _model = Store.GetOrCreate(_sessionKey);
    }

    private void Submit()
    {
        _model.CompletedSteps.Add(4);
        _submitted = true;
    }
}

